import * as React from "react";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export type ProgressType        = "linear" | "circular";
export type ProgressLinearSize  = "sm" | "md" | "lg" | "xl";
export type ProgressCircularSize = "xs" | "sm" | "md" | "lg" | "xl";

/* в”Җв”Җ Size maps в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const linearHeightMap: Record<ProgressLinearSize, string> = {
  sm: "h-[4px]",
  md: "h-[10px]",
  lg: "h-[20px]",
  xl: "h-[30px]",
};

const circularSizeMap: Record<ProgressCircularSize, number> = {
  xs: 16,
  sm: 30,
  md: 60,
  lg: 80,
  xl: 100,
};

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   ProgressIndicator
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface ProgressIndicatorProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "color"> {
  /** м„ нҳ• / мӣҗнҳ• */
  type?: ProgressType;
  /** 0 ~ 100 */
  value?: number;
  /** мөңлҢҖк°’ (кё°ліё 100) */
  max?: number;
  /** м„ нҳ• мӮ¬мқҙмҰҲ */
  linearSize?: ProgressLinearSize;
  /** мӣҗнҳ• мӮ¬мқҙмҰҲ */
  circularSize?: ProgressCircularSize;
  /** м§„н–ү мғүмғҒ (кё°ліё ac-primary-50) */
  color?: string;
  /** нҠёлһҷ мғүмғҒ (кё°ліё ac-gray-30) */
  trackColor?: string;
  /** лқјлІЁ н…ҚмҠӨнҠё */
  label?: string;
  /** нҚјм„јнҠё н‘ңмӢң м—¬л¶Җ */
  showValue?: boolean;
  /** indeterminate (лЎңл”© мғҒнғң) */
  indeterminate?: boolean;
}

const ProgressIndicator = React.forwardRef<HTMLDivElement, ProgressIndicatorProps>(
  (
    {
      className,
      type = "linear",
      value = 0,
      max = 100,
      linearSize = "md",
      circularSize = "md",
      color = "#FF6300",     /* ac-primary-50 */
      trackColor = "#ECECEC", /* ac-gray-30 */
      label,
      showValue = false,
      indeterminate = false,
      ...props
    },
    ref
  ) => {
    const pct = indeterminate ? 0 : Math.min(100, Math.max(0, (value / max) * 100));

    /* в”Җв”Җ м„ нҳ• в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
    if (type === "linear") {
      return (
        <div ref={ref} className={cn("flex flex-col gap-1.5 w-full", className)} {...props}>
          {/* лқјлІЁ + к°’ */}
          {(label || showValue) && (
            <div className="flex items-center justify-between gap-2">
              {label && <span className="text-sm text-foreground">{label}</span>}
              {showValue && !indeterminate && (
                <span className="text-sm font-medium text-foreground tabular-nums ml-auto">{Math.round(pct)}%</span>
              )}
            </div>
          )}
          {/* нҠёлһҷ */}
          <div
            role="progressbar"
            aria-valuenow={indeterminate ? undefined : value}
            aria-valuemin={0}
            aria-valuemax={max}
            aria-label={label}
            className={cn(
              "w-full rounded-full overflow-hidden",
              linearHeightMap[linearSize]
            )}
            style={{ backgroundColor: trackColor }}
          >
            {/* м§„н–ү л°” */}
            <div
              className={cn(
                "h-full rounded-full transition-all duration-slow",
                indeterminate && "animate-[indeterminate_1.5s_ease-in-out_infinite]"
              )}
              style={{
                width: indeterminate ? "40%" : `${pct}%`,
                backgroundColor: color,
              }}
            />
          </div>
        </div>
      );
    }

    /* в”Җв”Җ мӣҗнҳ• в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
    const size        = circularSizeMap[circularSize];
    const strokeWidth = Math.max(2, size * 0.1);
    const radius      = (size - strokeWidth) / 2;
    const circumference = 2 * Math.PI * radius;
    const dashOffset  = indeterminate ? circumference * 0.75 : circumference * (1 - pct / 100);

    return (
      <div ref={ref} className={cn("inline-flex flex-col items-center gap-2", className)} {...props}>
        <div className="relative inline-flex items-center justify-center" style={{ width: size, height: size }}>
          <svg
            width={size}
            height={size}
            viewBox={`0 0 ${size} ${size}`}
            role="progressbar"
            aria-valuenow={indeterminate ? undefined : value}
            aria-valuemin={0}
            aria-valuemax={max}
            aria-label={label}
            className={indeterminate ? "animate-spin" : undefined}
            style={indeterminate ? { animationDuration: "1s" } : undefined}
          >
            {/* нҠёлһҷ */}
            <circle
              cx={size / 2}
              cy={size / 2}
              r={radius}
              fill="none"
              stroke={trackColor}
              strokeWidth={strokeWidth}
            />
            {/* м§„н–ү */}
            <circle
              cx={size / 2}
              cy={size / 2}
              r={radius}
              fill="none"
              stroke={color}
              strokeWidth={strokeWidth}
              strokeLinecap="round"
              strokeDasharray={circumference}
              strokeDashoffset={dashOffset}
              transform={`rotate(-90 ${size / 2} ${size / 2})`}
              className={indeterminate ? undefined : "transition-all duration-slow"}
            />
          </svg>

          {/* мӨ‘м•ҷ к°’ н‘ңмӢң */}
          {showValue && !indeterminate && (
            <span
              className="absolute text-foreground font-semibold tabular-nums"
              style={{ fontSize: Math.max(10, size * 0.2) }}
            >
              {Math.round(pct)}%
            </span>
          )}
        </div>

        {/* лқјлІЁ */}
        {label && <span className="text-sm text-foreground text-center">{label}</span>}
      </div>
    );
  }
);
ProgressIndicator.displayName = "ProgressIndicator";

export { ProgressIndicator };