"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Variants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const badgeVariants = cva(
  "inline-flex items-center gap-1 font-medium whitespace-nowrap select-none rounded-xl border",
  {
    variants: {
      variant: {
        // в”Җв”Җ мғҒнғң м •ліҙ л°°м§Җ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        complete: "bg-ac-green-10 text-ac-green-60 border-ac-green-40",
        success:  "bg-ac-blue-10 text-ac-blue-60 border-ac-blue-40",
        warning:  "bg-ac-orange-10 text-ac-orange-60 border-ac-orange-40",
        fail:     "bg-ac-red-10 text-ac-red-60 border-ac-red-40",
        // в”Җв”Җ кё°нғҖ л©”нғҖ л°°м§Җ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        primary:  "bg-ac-white text-ac-primary-50 border-ac-primary-40",
        default:  "bg-ac-gray-30 text-ac-gray-80 border-ac-gray-70",
      },
      size: {
        xs: "h-[16px] px-1 text-[10px]", 
        sm: "h-[20px] px-1.5 text-xs",
        md: "h-[26px] px-2 text-xs",
        lg: "h-[32px] px-3 text-sm",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
);

/* в”Җв”Җ Props в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export interface BadgeProps
  extends React.HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof badgeVariants> {
  /** мўҢмёЎ м•„мқҙмҪҳ (м„ нғқ) */
  icon?: React.ReactNode;
}

/* в”Җв”Җ Component в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function Badge({ className, variant, size, icon, children, ...props }: BadgeProps) {
  return (
    <span className={cn(badgeVariants({ variant, size }), className)} {...props}>
      {icon && (
        <span className="shrink-0 flex items-center" aria-hidden="true">
          {icon}
        </span>
      )}
      {children}
    </span>
  );
}

export { Badge, badgeVariants };